import { buildInitParams, serializeInitParams } from "hono/router/reg-exp-router";

export function formatRouterInitSource(paths: string[]): string {
  const uniquePaths = Array.from(new Set(paths));
  const serialized = serializeInitParams(buildInitParams({ paths: uniquePaths }));
  return `// Generated by rinka — do not edit by hand.
// @ts-nocheck -- generated by rinka codegen; edits belong in packages/rinka/src/vite/*
/* oxlint-disable -- generated by rinka codegen; do not lint the codegen output */
import type { PreparedRegExpRouter } from "hono/router/reg-exp-router";

// prettier-ignore
export const routerParams: ConstructorParameters<typeof PreparedRegExpRouter> = ${serialized};
`;
}
